  private_constant :RustBufferStream

  # Helper for structured writing of values into a RustBuffer.
  class RustBufferBuilder
    def initialize
      @rust_buf = RustBuffer.alloc 16
      @rust_buf.len = 0
    end

    def finalize
      rbuf = @rust_buf

      @rust_buf = nil

      rbuf
    end

    def discard
      return if @rust_buf.nil?

      rbuf = finalize
      rbuf.free
    end

    def write(value)
      reserve(value.bytes.size) do
        @rust_buf.data.put_array_of_char @rust_buf.len, value.bytes
      end
    end

    def write_U16(v)
      v = IrohFfi.uniffi_in_range(v, 'u16', 0, 2**16)
      pack_into(2, 'S>', v)
    end

    def write_U32(v)
      v = IrohFfi.uniffi_in_range(v, 'u32', 0, 2**32)
      pack_into(4, 'L>', v)
    end

    def write_I32(v)
      v = IrohFfi.uniffi_in_range(v, 'i32', -2**31, 2**31)
      pack_into(4, 'l>', v)
    end

    def write_U64(v)
      v = IrohFfi.uniffi_in_range(v, 'u64', 0, 2**64)
      pack_into(8, 'Q>', v)
    end

    def write_I64(v)
      v = IrohFfi.uniffi_in_range(v, 'i64', -2**63, 2**63)
      pack_into(8, 'q>', v)
    end

    def write_Bool(v)
      pack_into(1, 'c', v ? 1 : 0)
    end

    def write_String(v)
      v = IrohFfi.uniffi_utf8(v)
      pack_into 4, 'l>', v.bytes.size
      write v
    end

    def write_Bytes(v)
      v = IrohFfi.uniffi_bytes(v)
      pack_into 4, 'l>', v.bytes.size
      write v
    end

