        write_String(v.local_addr)
      end
      if v.closed?
        pack_into(4, 'l>', 2)
        write_String(v.id)
        write_String(v.remote_addr)
        write_String(v.local_addr)
        write_TypePathStatsRecord(v.last_stats)
