      if v.selected?
        pack_into(4, 'l>', 3)
        write_String(v.id)
        write_String(v.remote_addr)
        write_String(v.local_addr)
      end
      return unless v.lagged?

      pack_into(4, 'l>', 4)
      write_U64(v.missed)
    end

